export const searchIndex: SearchEntry[] = [
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-1", subsectionNumber: "1.1", subsectionTitle: "Juvenile Committee Structure", text: "Juvenile Committee Structure. The Juvenile Committee oversees the day-to-day operation of the St Pats Donabate juvenile section. Ger Cohen Juvenile Games Chairperson Lead Juvenile Committee represent section at club executive meetings chair meetings coordinate mentor ratification. Traolach O'Donnell Academy Coordinator Boys and Girls 4yrs 7yrs Football LGFA Hurling Camogie. Elaine Walsh LGFA Coordinator Girls Under 8 Minor Football. Pat Martin Niamh Armstrong Camogie Coordinator Girls Under 8 Minor Camogie. Sheila McGuinness Children's Officers children's welfare safeguarding Garda Vetting. Juvenile Committee 2026 members: Ger Cohen Alan Quinn Eimear Drea Graham Owens Lorraine Halpin Nikki Murran Philip Bourke Ray Greene Traolach O'Donnell. Build a strong juvenile section with great coaching fun and development." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-2", subsectionNumber: "1.2", subsectionTitle: "Club Executive 2026", text: "Club Executive 2026. Chairperson Felim McAllister 086-8141908. Secretary Jayne Elmiger-Coffey 087-2961607. Vice-Secretary Sharon Burke 086-1503667. Treasurer Alan Merryman 086-8163249. Registrar Cormac Golden 087-7985897. Public Relations Officer Rory O'Neill 087-7841551. Juvenile Games Chairperson Ger Cohen 087-9879647. LGFA Secretary Elaine Walsh 087-9047440. Children's Officer Sheila McGuinness 086-3525113. Community Officer Shane Dowling 086-2303811. Health and Wellbeing Officer Shane Manton 087-7702002. Cultural Language Officer Fiachra O'hEochaidh 086-8675100." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-3", subsectionNumber: "1.3", subsectionTitle: "Key Contacts 2026", text: "Key Contacts 2026. Juvenile Games Chairperson Ger Cohen 087-9879647. Juvenile Secretary Jayne Elmiger-Coffey 087-2961607. Children's Officer Sheila McGuinness 086-3525113. Designated Liaison Officer DLO Lorraine Ni h'Ailpin 087-6284746. GPO Games Promotion Officer Traolach O'Donnel 087-4127090. Fixtures Coordinator Pitch Allocation Jayne Elmiger-Coffey 087-2961607. Football Referees Coordinator Dan Burke 087-4837990. Camogie Referees Coordinator Dan Burke 087-4837990. LGFA Secretary Elaine Walsh 087-9047440. Camogie Secretary Pat Martin 087-6229095. Club Registrar Cormac Golden 087-7985897." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-4", subsectionNumber: "1.4", subsectionTitle: "Dates for Juvenile Meetings 2026", text: "Dates for Juvenile Meetings 2026. All meetings are held at Ballymastone at 20:30. 6th February 2026 Ballymastone 20:30. 9th April 2026 Ballymastone 20:30. 11th June 2026 Ballymastone 20:30. 20th August 2026 Ballymastone 20:30. 13th October 2026 Ballymastone 20:30. 26th November 2026 Ballymastone 20:30. Mentors are encouraged to attend when agenda items relevant to their age group are being discussed. The Juvenile Secretary will circulate agendas in advance through ClubZap and email." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-5", subsectionNumber: "1.5", subsectionTitle: "Mentor Ratification", text: "Mentor Ratification. Mentors are ratified annually by the Club Executive. The Lead Mentor presents their proposed coaching team to the Juvenile Chairperson for the upcoming season including confirmation of Garda Vetting Safeguarding course completion coaching qualifications membership status. The Lead Mentor is responsible for effective communication within their coaching team and supporting the implementation of club policies. Any mid-season updates or changes to coaching teams must be submitted to the Club Executive through the Juvenile Chairperson. No mentor may take up a role with a juvenile team without being formally ratified." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-6", subsectionNumber: "1.6", subsectionTitle: "Club Subscriptions & Player Registration", text: "Club Subscriptions Player Registration. Only fully paid-up members will be registered with the club. Players who have not paid their membership fees will not be permitted to train or participate in matches. All mentors and coordinators must also be paid-up members of the club. Membership can be completed through the St Pats GAA Club website www.stpatsgaa.com. The annual membership deadline is 17th March. Lists of registered and paid-up members are maintained by the Club Registrar Cormac Golden." },
  { sectionId: "s1", sectionNumber: "1", sectionTitle: "Juvenile Overview", subsectionId: "1-7", subsectionNumber: "1.7", subsectionTitle: "Club Communications", text: "Club Communications. There are 4 formal channels of communication for teams results and events. Website stpatsgaa.com primary information hub. Twitter X @StPatsDonabate match results news. Instagram stpatsdonabate photos events. Facebook St Pats Donabate community updates. ClubZap is the official communication platform for all St Pats juvenile teams used for training notifications fixture details attendance tracking general updates." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-1", subsectionNumber: "2.1", subsectionTitle: "Role of Juvenile Mentor", text: "Role of Juvenile Mentor. Mentors train boys and girls arrange matches interact with referees and officials deal with bumps and bruises watch young players grow through the ranks. Core responsibilities: provide safe fun developmental environment plan deliver age-appropriate coaching sessions attend manage fixtures communicate effectively with parents uphold club values comply with safeguarding child welfare requirements. A good mentor puts welfare and development of children first plans sessions thinks ahead treats every player fairly remains calm positive communicates honestly with parents continues to learn." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-2", subsectionNumber: "2.2", subsectionTitle: "Role of Lead Mentor", text: "Role of Lead Mentor. The Lead Mentor is the primary contact person and responsible adult for the age group. Administration: confirm mentor team and role assignments ensure all mentors are vetting-compliant and ratified submit mentor list for ratification manage competition entries team sheet submissions communicate fixtures training schedules. Coaching: lead planning of season's coaching programme ensure session plans are prepared and age-appropriate oversee player development coordinate streaming panel decisions. Safeguarding: ensure all mentors within the group are compliant know Children's Officer and DLO contact details handle welfare concerns appropriately." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-3", subsectionNumber: "2.3", subsectionTitle: "Suggested Mentor Roles", text: "Suggested Mentor Roles with Each Group. Lead Mentor Head Coach primary responsible adult main point of contact. Assistant Coach supports Lead Mentor in session delivery. Team Administrator manages match-day logistics communicates with parents handles team sheet preparation manages ClubZap Teamer group. Welfare Officer within team supports safeguarding awareness first point of contact for parent welfare queries liaises with Children's Officer. First Aid Lead responsible for first aid kit at sessions and matches manages injury concussion response maintains incident records." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-4", subsectionNumber: "2.4", subsectionTitle: "Team Management Structures", text: "Suggested Team Management Structures. CCC1 Age Groups U8-U12 minimum team structure 1 Lead Mentor 2-3 Assistant Mentors 1 Team Parent Administrator. CCC2 Age Groups U13+ 1 Lead Mentor 1-2 Specialist Coaches 1 Team Manager 1 Physio Welfare Lead. Where an age group has A and B and C teams the overall coaching group works together for streaming panel reviews cross-group training sessions shared coaching philosophy and standards." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-5", subsectionNumber: "2.5", subsectionTitle: "Season & Session Planning", text: "Importance of Season and Session Planning. Seasonal Planning: agree coaching philosophy LTAD priorities season structure streaming panel approach communication plan. Every training session should be planned in advance. A good session plan includes objective warm-up main activity conditioned game cool-down. Review points: start of season after Easter after summer break end of season. Sample Annual Plan Appendix 27 Sample Annual Calendar Appendix 26 for templates." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-6", subsectionNumber: "2.6", subsectionTitle: "Coaching & Games Development", text: "Coaching and Games Development. GAA coaching development pathway accessible through Tobar GAA online learning platform. Foundation Introduction to Coaching Gaelic Games ICGG all new mentors mandatory. Award 1 Award 2 coaching pathways. Dublin GAA Games Development unit provides coaching workshops CPD sessions skills development resources. St Pats encourages player-centred game-based approach maximise time with ball minimise standing and listening create opportunities for players to solve problems provide positive specific feedback make sessions fun and energetic." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-7", subsectionNumber: "2.7", subsectionTitle: "Mentor Development", text: "Mentor Development. Every mentor must complete before being active with any juvenile team: Garda Vetting through club Registrar. Safeguarding 1 Child Safeguarding Awareness on Tobar renewed every 3 years. ICGG Foundation Course entry-level GAA coaching qualification on Tobar. Foireann Registration as paid-up club member. Club Ratification approved by Club Executive. Recommended: First Aid CPR strongly recommended. Award 1 Coach Education. Dublin GAA workshops. GPO available for coaching advice session ideas games development support." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-8", subsectionNumber: "2.8", subsectionTitle: "Additional Coaching Resources", text: "Additional Coaching Resources. Tobar learning.gaa.ie coaching courses safeguarding cert learning resources. Dublin GAA Games Dev dublingaa.ie workshops coaching supports skills development. GAA Official Website gaa.ie rules governance coaching resources. LGFA Official lgfa.ie ladies football rules coaching information. Camogie Association camogie.ie camogie regulations coaching resources. Key Documents: LTAD Cheat Sheet Appendix 23 Go Games Activities Guidebook Appendix 15 Session Planners Appendices 28-32 Player Skills Charts Appendices 36 37 38." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-9", subsectionNumber: "2.9", subsectionTitle: "Foireann and Tobar", text: "Foireann and Tobar Management. Foireann is the GAA's official administration and registration platform. Used for club membership registration Garda Vetting processing safeguarding course certification coaching qualification records generating official team sheets player and mentor registration numbers. Register at foireann.ie complete your profile contact Club Registrar Cormac Golden to be linked to St Pats. Tobar is the GAA's official online learning and coaching platform at learning.gaa.ie. Available: Safeguarding 1 mandatory renewed every 3 years ICGG Award 1 Award 2 coaching pathways CPD modules." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-10", subsectionNumber: "2.10", subsectionTitle: "Sponsorship", text: "Sponsorship and Timing of Sponsorship. All sponsorship arrangements for juvenile teams must be approved through the club before being agreed or announced. Individual teams are not permitted to enter independent sponsorship agreements. Process: Contact Juvenile Chairperson or Club Secretary with sponsorship proposal Club Executive reviews approves or declines proposal. Sponsor logos on jerseys or team materials require club approval. All sponsorship funds pass through the Club Treasurer. Fundraising: table quizzes cake sales supermarket bag packing other locally approved initiatives." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-11", subsectionNumber: "2.11", subsectionTitle: "First Aid Training", text: "First Aid Training. All mentors are strongly encouraged to hold current First Aid CPR certification. First Aid Kit: every team must have access to properly stocked first aid kit at all training sessions and matches containing antiseptic wipes plasters bandages dressings ice packs emergency contact list incident report forms. Emergency Procedure: call 999 or 112 do not move player who may have spinal or neck injury administer basic first aid if trained contact parent guardian immediately inform Children's Officer and Juvenile Chairperson. Concussion Protocol: If in doubt sit them out. Any player suspected of concussion must be removed from play immediately." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-12", subsectionNumber: "2.12", subsectionTitle: "Player Injury Schemes & Reporting", text: "Player Injury Schemes and Injury Reporting. GAA Injury Fund for registered members. Claims process: medical treatment sought promptly incident reported to club Lead Mentor Juvenile Committee claim form submitted through Club Secretary medical receipts submitted. Only registered paid-up members are eligible. Injury Reporting: record date time location of incident name of player nature of injury who was present what action was taken parents guardian notified whether emergency services were called. Serious incidents must be reported to Juvenile Chairperson." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-13", subsectionNumber: "2.13", subsectionTitle: "Annual Parents Meeting", text: "Annual Parents Meeting. Should take place before first competitive fixture ideally January February. Recommended Agenda: welcome introduce coaching team season overview club philosophy team structure streaming approach playing time policy attendance and commitment expectations communication ClubZap sideline behaviour safeguarding Child Protection overview medical info request. Key points: membership registration deadlines mouthguard requirement helmet requirement hurling camogie emergency contact and medical information process team communication channels. See Team Parent Meeting Template Appendix 39." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-14", subsectionNumber: "2.14", subsectionTitle: "Annual Calendar & Key Dates", text: "Sample Annual Calendar and Key Dates. January registration opens streaming panel reviews parents meeting. February first training sessions begin Go Games and league entries. March membership deadline 17th March season underway. April mid-season review Easter break considerations. May June Feile preparations county qualifiers summer window. July school holidays reduced schedule. August return to training pre-championship preparation. September championship competitions begin. October grading for following year begins U12 and above. November end-of-season reviews planning for following year. December quieter period social events admin preparation." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-15", subsectionNumber: "2.15", subsectionTitle: "Code of Best Practice", text: "Code of Best Practice. GAA Code of Best Practice in Youth Sport sets out standards expected of all adults working with children in Gaelic Games. Appendix 12. Every child has the right to participate in sport in safe enjoyable environment be protected from abuse neglect exploitation have their views heard and respected be treated with fairness and dignity. Adults working with children must prioritise welfare of child avoid one-to-one situations with children never use physical punishment or emotional abuse maintain appropriate professional boundaries report any concerns about child welfare immediately." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-16", subsectionNumber: "2.16", subsectionTitle: "Child Protection", text: "Child Protection. All juvenile mentors are mandated persons under the Children First Act 2015. Legally required to report reasonable grounds for concern about child welfare to Tusla Child and Family Agency. Children's Officer Sheila McGuinness 086-3525113. Designated Liaison Officer DLO Lorraine Ni h'Ailpin 087-6284746. Tusla 01-7718500. Emergency 999 112. Reporting Procedure: listen carefully do not interrupt stay calm reassure child do not promise confidentiality record accurately contact DLO immediately do not discuss with other mentors parents or alleged abuser. If child is in immediate danger call 999 112 first. Child Safeguarding Statement Appendix 6." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-17", subsectionNumber: "2.17", subsectionTitle: "Complaints Procedure", text: "Complaints Procedure. Step 1 Informal Resolution: many concerns can be resolved informally through direct respectful conversation speak directly with Lead Mentor or Juvenile Chairperson. Step 2 Formal Complaint: submitted in writing to Juvenile Chairperson clearly describe nature of concern include relevant dates names events. Step 3 Escalation: if complaint cannot be resolved at Juvenile Committee level may be escalated to Club Executive. Child welfare and safeguarding complaints handled under Child Protection Procedure by DLO and Children's Officer. All complaints handled respectfully and confidentially." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-18", subsectionNumber: "2.18", subsectionTitle: "Communications & Social Media", text: "Communications and Social Media. ClubZap is the official communication platform for all St Pats juvenile teams. Permitted: group messages to parents via ClubZap team WhatsApp groups with parents and multiple mentors email communications to a parent group. Not Permitted: private one-to-one messages between adult mentor and individual player communicating with players via personal social media accounts adding players as social media friends or followers sharing images of children without explicit parental consent. Written consent must be obtained from parents before photographs or video of players are taken images are shared on social media players are named in match reports." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-19", subsectionNumber: "2.19", subsectionTitle: "Social Media Posting Guidelines", text: "Social Media Posting Guidelines. Be positive posts should be uplifting and constructive. Respect privacy never identify children by name in public posts. Seek consent always obtain parental consent before posting images of children. Protect location information do not publish training locations or travel arrangements publicly. Respect opponents never post negative comments about opposing clubs players or mentors. Respect referees criticism of referees on social media is never acceptable. Report concerns any inappropriate content involving children must be reported to Children's Officer immediately. Official St Pats accounts managed by PRO Twitter X @StPatsDonabate Instagram stpatsdonabate Facebook St Pats Donabate." },
  { sectionId: "s2", sectionNumber: "2", sectionTitle: "The Juvenile Mentor", subsectionId: "2-20", subsectionNumber: "2.20", subsectionTitle: "Points of Contact for Juvenile Teams", text: "Current Points of Contact for Juvenile Teams. Internal team contact documents updated annually available in Juvenile Downloads section of Dublin GAA website. Juvenile Hurling Contacts 2026 current mentor and contact information for all hurling teams. Juvenile Football Contacts 2026 current mentor and contact information for all football teams. LGFA Camogie Club Mentor Contact List updated as of 17th March 2026. Contact lists are for internal use within the coaching community and should not be shared publicly or posted on social media. If your contact details change during the season please notify the Juvenile Secretary." },
  { sectionId: "s3", sectionNumber: "3", sectionTitle: "Player Development", subsectionId: "3-1", subsectionNumber: "3.1", subsectionTitle: "Nursery Programme Overview", text: "Nursery Programme Overview. The St Pats Nursery Programme is the club's Academy for children aged approximately 4 to 7 years U4 to U7. Over 200 children participate in the St Pats Academy every Saturday morning making it one of the most active and vibrant in the county. At Nursery level the emphasis is entirely on fun and fundamentals. No competition no scores and no selection. Every child participates. Activities designed around running jumping hopping skipping and catching basic hand and foot skills games and activities that build coordination and confidence short energetic activities with high levels of movement. Success measured by: do the children enjoy themselves do they leave wanting to come back next week are they making friends. Academy Coordinator Traolach O'Donnell. Nursery Resource Pack Appendix 24 Nursery Programme Mentor Summary Appendix 35." },
  { sectionId: "s3", sectionNumber: "3", sectionTitle: "Player Development", subsectionId: "3-2", subsectionNumber: "3.2", subsectionTitle: "Player Passport Instructions", text: "Player Passport Instructions. GAA Player Passport is a youth athletic development platform used to assess track and support individual player development. Includes Movement Screening assessing basic movement patterns and physical literacy Skills Challenges age-appropriate skills assessments Player Profile tracking individual progress over time. Players are assessed using standardised skills challenges appropriate for their age group. Results recorded on Player Passport platform. Assessments can be repeated at intervals to track progress. Data supports individual coaching plans and player development conversations. GPO coordinates Player Passport activities within St Pats. Benchmark player ability identify individual development needs motivate players with measurable goals inform streaming and panel decisions." },
  { sectionId: "s3", sectionNumber: "3", sectionTitle: "Player Development", subsectionId: "3-3", subsectionNumber: "3.3", subsectionTitle: "Skill List by Age Group", text: "Suggested Skill List by Age Group. U8-U9 FUNdamentals Football: catch kick left and right hand-pass solo run. Hurling Camogie: hold hurley correctly ground strike lift and carry. Focus: fun lots of ball contact basic movement patterns enjoyment. U10-U11 Learning to Train Early Football: catch high and low kick accuracy hand-pass moving solo ground ball. Hurling Camogie: ground strike overhead strike hand-pass solo carry first touch. U12 Learning to Train Late Football: all basics with accuracy blocking tackling positional awareness. U13-U14 Training to Train Football: all skills under pressure team play patterns kickouts scoring from play. U15-U16 Training to Compete: full game skills at pace leadership on pitch decision-making under competitive pressure. See skills charts Appendices 36 37 38." },
  { sectionId: "s3", sectionNumber: "3", sectionTitle: "Player Development", subsectionId: "3-4", subsectionNumber: "3.4", subsectionTitle: "Long-Term Athletic Development (LTAD)", text: "Long-Term Athletic Development LTAD. Framework for developing young athletes in line with their physical mental and emotional growth. LTAD Stages: Active Start Under 6 fun movement no structured sport. FUNdamentals U6-U9 basic motor skills fun all sports. Learning to Train U10-U12 critical skill window high repetition game-based. Training to Train U13-U15 physical development alongside technical skills. Training to Compete U16-U18 performance preparation mental skills. Training to Win 18+ full competitive preparation. The Learning to Train stage approximately U10-U12 is the most important period for skill acquisition. Technical skills developed or not developed at this stage tend to be retained long-term. Maximise ball contact and repetition at U10-U12. Avoid over-specialisation children should be exposed to multiple codes and sports. LTAD Cheat Sheet Appendix 23." },
  { sectionId: "s3", sectionNumber: "3", sectionTitle: "Player Development", subsectionId: "3-5", subsectionNumber: "3.5", subsectionTitle: "Healthy Eating, Hydration & Nutrition", text: "Healthy Eating Hydration and Player Nutrition. Before Training Match: eat balanced meal 2-3 hours before activity carbohydrates protein vegetables avoid heavy or greasy foods drink water in hours leading up. During Training Match: players should have their own water bottles at every session mandatory regular water breaks avoid sugary sports drinks for normal training sessions. After Training Match: refuel within 30-60 minutes with balanced snack or meal rehydrate water is the best choice rest and recovery are as important as nutrition. Mentors role: remind players and parents of water bottle requirements build hydration breaks into sessions. Guide for Coaches Healthy Eating for Sport Appendix 16. Guide for Parents Healthy Eating for Sport Appendix 17." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-1", subsectionNumber: "4.1", subsectionTitle: "Juvenile Games Structures & Regulations", text: "Juvenile Games Structures and Regulations. CCC1 Go Games U8-U12 non-graded development-focused. CCC2 Graded U13-Minor graded league and championship. CCC1 Dublin GAA County Committee for Children: every player on the panel must play in every game no official league tables or standings modified formats appropriate to age group. CCC2 competitive graded league and championship structures from U13 onwards. Team sheets mandatory using Foireann. Referee appointments through County Board structures. Girls competitions: LGFA Dublin LGFA Go Games then graded leagues championship. Camogie Dublin Camogie Go Games then graded leagues championship. CCC1 Regulations 2025 Appendix 4. CCC2 Regulations 2025 Appendix 5." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-2", subsectionNumber: "4.2", subsectionTitle: "Playing Games Overview / Rules of Play", text: "Playing Games Overview Rules of Play. Football Go Games Format: U8 7-a-side small pitch Size 3 ball. U9 7-a-side Size 3. U10 9-a-side Size 3 or 4. U11 11-a-side Size 4. U12 13-a-side Size 4. Substitutions unlimited every player must participate. Rule Enhancements: 40m scoring arc 2-point scores kick-out mark beyond 40m solo-and-go free kicks 3v3 structure rule. Hurling Go Games: U8 7-a-side soft sponge sliotar. U9 7-a-side Size 3. U10 9-a-side Size 3. U11 11-a-side Size 4. U12 13-a-side Size 4. Camogie: mandatory helmet with full facial guard 15-a-side standard hooking and blocking permitted goal equals 3 points hand-pass may score a point only." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-3", subsectionNumber: "4.3", subsectionTitle: "Equipment & Requisition Process", text: "Purchase of Equipment Requisition Process. Equipment must be ordered centrally. Ordering Process: Juvenile Chairperson and Vice Secretary advise Lead Mentors when next order window is open teams submit all equipment requests all requests reviewed against available club funds ordered centrally by club. Teams are not permitted to place independent orders directly with suppliers unless expressly authorised. Standard Team Equipment: footballs sliotars bibs cones first aid kits. Mouthguards: all juvenile players must wear a mouthguard for all football training sessions and matches no exceptions. Players without a mouthguard must not take part in football activity." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-4", subsectionNumber: "4.4", subsectionTitle: "Mobile Goals / Goal Safety", text: "Mobile Goals and Goal Safety. Goal safety is a non-negotiable duty of care responsibility. Mobile goals must always be secured correctly using sandbags heavy rubber weights clips or other approved anchoring methods. Goals must be stable at all times when in use. Mobile goals must be returned to designated storage areas after every use. Under no circumstances should children be allowed to climb swing or hang from goals. Mentors must check goal stability before every training session and match. Slalom poles may be used with younger age groups exercise caution as pointed ends present a safety risk. Lead Mentors should locate flags and goals prior to matches to ensure the pitch is ready for a timely throw-in." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-5", subsectionNumber: "4.5", subsectionTitle: "Mouth Guards", text: "Mouth Guards. All juvenile players must wear a mouth guard for all football training sessions and matches without exception in line with GAA and LGFA regulations. Any player without a mouth guard must not take part in football activity. Players participating in a game without a mouth guard may receive a card from the referee. Parents and guardians should be reminded of the mouth guard requirement at the Annual Parents Meeting at the start of the season via ClubZap and periodically throughout the year. The Irish Dental Association recommends custom-fitted mouth guards for pre-teens teenagers and adults. Mentors can recommend that parents speak to their dentist about a custom-fitted guard." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-6", subsectionNumber: "4.6", subsectionTitle: "Kit / Jersey / Uniform / Coaches Bibs", text: "Kit Jersey Uniform Coaches Bibs. CCC1 U8-U12 official match-day kit: club jersey O'Neills club shorts or skorts club socks. CCC2 U13+ additional requirements: numbered jerseys for official fixtures. Match jerseys from U13 upwards should remain under mentor control for games and competitions. Only approved club match jerseys O'Neills should be worn for official games unless otherwise agreed by the club. Lead Coach is responsible for overall presentation and organisation of team on match day. Mentors must comply with county board requirements regarding coaches bibs sideline identification official match-day regulations. Mentors should wear bibs at all competitive fixtures." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-7", subsectionNumber: "4.7", subsectionTitle: "What is Streaming?", text: "What is Streaming. Streaming is placing players of similar ability on the same team as opposed to having mixed-ability groups playing together. Central purpose is player development particularly for players who are not among the strongest in the group. Players get more ball involvement compete at appropriate level build confidence and skills have more fun. Streaming is a player-centred process. Mentors aim to find the right team for each player in order to develop their confidence skills and participation. Standard approach: rank all players by ability and assign them to teams. Alternative approach: rank players but establish a group of marginal A B or B C players who alternate between teams. Players develop at different rates panels should be reviewed at start of season after Easter after summer break." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-8", subsectionNumber: "4.8", subsectionTitle: "St Pats Policy on Streaming", text: "St Pats Policy on Streaming. The goal is not to label children or create fixed groups. Streaming is player-centred about development not ego. It should improve challenge and ball involvement for players at all ability levels. Reviewed regularly and is never fixed for the whole year. The wider age group should still feel like one group. Parents should understand the why before they focus on the label. Training together maintains group identity and makes movement between panels more natural. Club encourages a blended approach to streaming. No player should have a fixed place on any one team for a full season. Coaches should rotate among teams to ensure all players get access to all coaches. Boys Football and Hurling streaming begins at U9. Girls Football and Camogie teams graded at start of each year in January." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-9", subsectionNumber: "4.9", subsectionTitle: "Referees", text: "Referees. Naomh Padraig Donabate is committed to creating an environment where referees including juvenile referees feel valued respected and supported. Before the Match: for Go Games the Lead Mentor is encouraged to brief the referee before throw-in. Abuse intimidation sarcasm or persistent questioning of referees is not acceptable under any circumstances. Referee Appointments: CCC1 U8-U12 club may provide home referees coordinated through referee coordinators. CCC2 U13+ referees appointed through County Board structures. Home team is responsible for: contacting referee in advance to confirm availability confirming venue throw-in time and pitch details notifying referee immediately of any changes or cancellations. Failure to notify referee of changes may result in referee fees still being payable." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-10", subsectionNumber: "4.10", subsectionTitle: "Team Sheet Submissions", text: "Team Sheet Submissions. CCC1 U8-U12 team sheets are not required in most CCC1 competitions. Camogie exception: team sheets required for every second fixture from U8 every fixture from U9 up submit via gogames.dublin@camogie.ie. CCC2 U13+ team sheets are mandatory for all CCC2 games. How to generate: navigate to foireann.ie or Foireann app select registered team download official Foireann team sheet fill in player numbers opposition date hand to referee before throw-in. Required information: player registration numbers mentor management registration numbers player jersey numbers for CCC2. LGFA team sheet rules vary by competition. Camogie CC2 Foireann team sheets required must be signed by authorised official failure may result in a fine." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-11", subsectionNumber: "4.11", subsectionTitle: "Return of Match Results", text: "Return of Match Results. CCC2 Football and Hurling results submitted through designated channels to Dublin GAA. LGFA results submitted through Dublin LGFA channels. Camogie results submitted through Dublin Camogie channels. Results should be submitted promptly after each match. Late or missing result submissions can affect league table accuracy result in administrative penalties cause issues with grading calculations. Where a game is not played or postponed the Home Mentor must email: GAA Hurling juvresults@dublingaa.ie Camogie gogames.dublin@camogie.ie LGFA smallsidedgamesdlgfa@gmail.com. Email should clearly state the reason the fixture did not take place." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-12", subsectionNumber: "4.12", subsectionTitle: "Challenge Matches / Friendly Games", text: "Challenge Matches and Friendly Games. Challenge games and friendly fixtures give players additional game experience allow mentors to test game plans in low-pressure environments provide opportunities for players who may not be getting as much competitive action build relationships with other clubs. Before arranging any challenge match check pitch availability with Fixtures Coordinator do not agree a fixture before confirming pitch availability. Submit request through official pitch booking process. Challenge game pitch allocations should alternate between home and away. LGFA Requirements: LGFA Secretary must submit request for approval to county board minimum 48 hours in advance including name of host club visiting clubs location date time number of teams participating duration of event. Submit to stpatricksdonabate.dublin@lgfa.ie." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-13", subsectionNumber: "4.13", subsectionTitle: "Féile Competitions", text: "Feile Competitions. Feile na nGael hurling camogie and Feile Peil na nOg football is the largest underage GAA festival in the world. Takes place annually at U14 level. Phase 1 County Qualifiers: teams compete in county-level qualifiers in Dublin only qualifying teams progress to national finals. Phase 2 National Finals: held over a long weekend at designated host venues around Ireland teams stay in host family homes representing club and county. Feile Rules 2025 Appendix 10. Feile Checklist for Mentors Appendix 11. John West Feile Charter 2025 Appendix 18. Planning must begin at least 9 months in advance. Key areas: player selection and panel communication fundraising for travel accommodation county qualifier schedule host family coordination travel arrangements." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-14", subsectionNumber: "4.14", subsectionTitle: "Fulfilment of Fixtures", text: "Fulfilment of Fixtures. Fulfilling fixtures respects opponents referees county boards and your own players. Chronic late withdrawals damage player trust opponent preparation and club reputation. Confirm availability early in the week not on match day escalate likely issues immediately rather than at the last minute. If a fixture cannot be fulfilled notify the club and opposition at the earliest realistic opportunity. Chronic late withdrawals are unacceptable. Process for Non-Fulfilment where a game is not played or postponed Home Mentor must email: GAA Football Hurling juvresults@dublingaa.ie Camogie gogames.dublin@camogie.ie LGFA smallsidedgamesdlgfa@gmail.com. Email should clearly outline the reason the fixture did not take place." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-15", subsectionNumber: "4.15", subsectionTitle: "Playing Within Age", text: "Club Policy on Playing Within Age. The club's default position is that players must train and play within their natural age group. Playing up may be appropriate in limited circumstances but should never undermine the younger player's own team or displace older players unfairly. Rules for Playing Up: parent guardian consent is required. A younger player's own age-group fixture takes priority in the event of a clash. The child's welfare confidence and development must outweigh short-term team convenience. Resolving Disagreements: refer to Juvenile Chairperson for a decision if either mentor disagrees may be appealed to the Club Executive. Full playing-up policy available at Appendix 34 St Pats GAA Juvenile Playing Policy Age. Players should not be pressured to play up." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-16", subsectionNumber: "4.16", subsectionTitle: "Competitive Teams", text: "Competitive Teams. From the point at which an age group has multiple teams and enters graded competition some teams may operate at a more competitive level than others. All teams should aim to be as competitive as possible within the capability of that individual team but not at the expense of equal development opportunities for all players. Parents and players should understand the expectations before the season starts. At younger ages development and broad game involvement remain the priority. At older youth stages commitment player attitude and the needs of the game may have a greater influence on playing time. Lower-graded teams must receive equally strong coaching support. The annual parents meeting is the right forum for this conversation." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-17", subsectionNumber: "4.17", subsectionTitle: "Grading Principles", text: "Grading Principles. From U12 Boys and U13 Girls onwards teams compete in grading games to determine the most appropriate division for the upcoming season. The purpose of grading is to place teams where they can compete appropriately develop their skills and continue to enjoy their games not to win divisions at all costs. St Pats goal during grading is to enter teams in the most competitive league possible while ensuring games remain competitive and enjoyable players develop with confidence teams win approximately 40-60% of games over a season. A players play at A level only. A B players may move between A and B panels. B C players may move between B and C panels. C players remain at C until ready to progress. These groupings are guidelines only never permanent labels. Grading is always player-centred and development-focused. Development attitude attendance effort and commitment all form part of grading decisions." },
  { sectionId: "s4", sectionNumber: "4", sectionTitle: "Playing Games", subsectionId: "4-18", subsectionNumber: "4.18", subsectionTitle: "Guidance on Player Nominations", text: "Guidance on Nominations of Players. Intercounty and Player Development Programme PDP opportunities can be positive and rewarding experiences for players. LGFA Player Development Programme PDP provides players with access to additional high-quality coaching outside their club. Typically covers U13 U15 U17. Dublin LGFA contacts the club secretary when nominations are sought deadline is tight begin identifying potential nominees from January. Intercounty Trials GAA Football and Hurling: at U14 Dublin GAA contacts lead mentor regarding 7-a-side Talent Identification blitz each club can bring maximum 10 U14 players minimum 7 from correct birth year. Selection criteria: skill most important speed intensity commitment interest in sport. All nominations must go through a small Selection Group not a single individual. Player welfare and long-term development always come before short-term success or reputation." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-1", subsectionNumber: "5.1", subsectionTitle: "Ballymastone Facilities Overview", text: "Ballymastone Facilities Overview. Ballymastone is the central training and match venue for all adult and juvenile teams at Naomh Padraig Donabate. Facilities: three full-sized grass pitches all-weather pitch ball wall gym access dressing rooms clubhouse. Location Saint Patrick's GAA Club Robbie O'Farrell Park Portrane Demesne Portrane Co Dublin Eircode K36 A3E7. Pitch access and training allocations coordinated by Pitch Allocation Fixtures Coordinator Jayne Elmiger-Coffey. Teams should only use pitches and time slots officially assigned to them. All members must respect any Pitch Closed notices. Goals equipment and shared areas must be left safely and respectfully after every use." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-2", subsectionNumber: "5.2", subsectionTitle: "Pitch Equipment", text: "Pitch Equipment. Lead Mentors should be provided with access to certain pitch-side facilities and equipment storage areas. Access may include ball wall dressing rooms all-weather pitch facilities. All keys and access privileges are club property and should be used responsibly. Keys must not be copied or shared without authorisation. Equipment storage: mobile goals nets and training equipment must be stored safely and securely after every use. Storage containers and equipment areas are shared club resources leave them tidy and ready for the next group. Each age group has an allocated storage section generally shared between boys and girls teams within the same age group. Teams move into the storage section assigned to their new age grade each January." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-3", subsectionNumber: "5.3", subsectionTitle: "Fixtures & Pitch Bookings", text: "Fixtures and Pitch Bookings. The Pitch Allocation Team Fixtures Coordinator Jayne Elmiger-Coffey has sole responsibility for all official pitch bookings and allocations. All booking requests and fixture enquiries must be sent to Pitch Allocation Team. Only requests submitted through the official process will be considered. Before organising a challenge match check pitch availability first. Early communication is strongly encouraged late requests significantly reduce the chance of a solution. The live training and pitch allocation schedule is maintained separately as a Google Sheet and should always be treated as the most up-to-date reference. For challenge games pitch allocations should alternate between home and away fixtures to protect and preserve club pitches." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-4", subsectionNumber: "5.4", subsectionTitle: "Training Schedules", text: "Training Schedules. Slots assigned to age groups not to individual A B C teams. Younger groups earlier evening slots where possible. Frequency two training opportunities per week subject to availability. Winter allocation balance between all-weather ball wall and grass pitches. Winter grass one all-weather ball-wall plus one grass per week where conditions allow. Mentors should always check the live training schedule before requesting changes or additional access. The schedule is maintained as a live Google Sheet link available through the Juvenile Secretary. Where additional capacity becomes available some extra allocations may be provided to older competitive teams where appropriate but this is at the discretion of the Pitch Allocation Team and cannot be assumed." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-5", subsectionNumber: "5.5", subsectionTitle: "Storage", text: "Storage. Naomh Padraig Donabate currently has two shared storage containers on site. Each age group has an allocated storage section generally shared between boys and girls teams of the same age group. Age groups move into the storage section assigned to their new age grade each January the sections remain fixed while teams progress through them. Storage Rules: storage areas are shared club resources keep them organised safe and usable for all groups. Teams should only use their allocated section. Remove broken damaged or unused equipment regularly. Label helmets bottles tops and specialty equipment clearly where possible. Shared containers should be left tidy after every session. Equipment must not block walkways exits or shared access points." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-6", subsectionNumber: "5.6", subsectionTitle: "Lighting", text: "Pitch Lighting. Only approved personnel should operate pitch lighting systems. Do not leave lights running unnecessarily after sessions or matches. If you are the last group using a lit area you are responsible for ensuring the lights are turned off. Report any faults or lighting issues promptly to the Grounds Team. Light switches for the all-weather pitch ball wall and near side of Pitch 1 are located in the clubhouse. Turn right at the Committee Room. Labelled switches are located behind the doors directly ahead. Pitch 2 instructions can also be found here." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-7", subsectionNumber: "5.7", subsectionTitle: "Lost Property", text: "Lost Property. Any lost property found should be placed in the designated lost property area in the back left dressing room of the clubhouse. Use team ClubZap channels to notify parents of missing or recovered items. Coaching groups should periodically remind parents and players to label helmets bottles tops jackets and personal gear. Encourage players to label all personal equipment clearly. Carry out a quick sweep of the training area at the end of each session. Remind parents and players at the start of each season." },
  { sectionId: "s5", sectionNumber: "5", sectionTitle: "Pitches & Facilities", subsectionId: "5-8", subsectionNumber: "5.8", subsectionTitle: "All-Weather Pitch & Ball Wall", text: "All-Weather Pitch and Ball Wall. The all-weather pitch at Ballymastone provides a year-round training surface that is not weather-dependent. Access is by key Lead Mentors should request access through Juvenile Chairperson or Fixtures Coordinator. All-weather pitch allocations managed through the live pitch schedule. Normal pitch rules apply goals must be secured equipment returned to storage lights turned off. Ball wall is a valuable facility for individual and small-group skill development. Access is by key. Sessions at the ball wall should be planned in advance and included in the allocation schedule. The ball wall is particularly useful for hurling camogie and football striking practice. Winter allocations typically include a ball wall slot for each age group. All keys are club property if assigned a key keep it safe do not copy or share without authorisation report lost keys to the Grounds Team immediately." },
  { sectionId: "s6", sectionNumber: "6", sectionTitle: "Resources & Appendices", subsectionId: "6-1", subsectionNumber: "6.1", subsectionTitle: "Useful Links & Online Resources", text: "Useful Links and Online Resources. Club Resources: St Pats Donabate Website stpatsgaa.com membership fixtures news downloads policies. ClubZap official communication platform. St Pats on X Twitter @StPatsDonabate news fixtures match results. St Pats Instagram stpatsdonabate. St Pats Facebook. Pitch Allocation Spreadsheet live weekly pitch allocation. Club Child Protection Section safeguarding guidance Code of Behaviour Garda Vetting info. Coaching Resources: Tobar learning.gaa.ie coaching courses safeguarding cert CPD. GAA Official Website gaa.ie. Dublin GAA dublingaa.ie county board regulations CCC fixtures forms. Dublin Ladies Gaelic Football dublinladiesgaelic.ie. LGFA Official lgfa.ie official guide 2026. Camogie Association camogie.ie. Administration: Foireann foireann.ie membership vetting qualifications team sheets. Player Passport youth athletic development skills challenge platform." },
  { sectionId: "s6", sectionNumber: "6", sectionTitle: "Resources & Appendices", subsectionId: "6-2", subsectionNumber: "6.2", subsectionTitle: "Mentor Checklists", text: "Mentor Checklists. 10 interactive checklists to help mentors stay prepared throughout the season. Progress is saved automatically. 1 Mandatory Mentor Compliance before any mentor is active with a team. 2 Pre-Season Planning at the start of each season. 3 Start-of-Season Coaching first weeks of the season. 4 Term Block Planning every 6-8 weeks. 5 Weekly Coaching Session before during after each training session. 6 Matchday Preparation before during after each fixture. 7 Referee and Fixture each weekly fixture. 8 Safeguarding and Welfare ongoing throughout season. 9 Equipment and Facilities regular equipment check. 10 End-of-Season at the end of each season." },
  { sectionId: "s6", sectionNumber: "6", sectionTitle: "Resources & Appendices", subsectionId: "6-3", subsectionNumber: "6.3", subsectionTitle: "Appendices", text: "Appendices. 38 reference documents available in the St Pats Juvenile Handbook 2026. Categories: Regulations and Rules CCC1 and CCC2 regs LGFA and Camogie guides Go Games rules Feile rules. Safeguarding and Welfare Child Safeguarding Statement GAA Code of Best Practice. Club Policies playing policy gear order form. Coaching Resources LTAD cheat sheet Go Games activities skills workshops nursery resources. Player Development skills charts Football Hurling Camogie LGFA LGFA development guidebook. Health and Wellbeing healthy eating guides for coaches and parents. Planning and Templates session planners annual calendars parent meeting template six-week blocks." }
];
